class Tonemap(NodeBuilder):
    """
    Map one set of colors to another in order to approximate the appearance of high dynamic range
    """

    _bl_idname = "CompositorNodeTonemap"
    node: bpy.types.CompositorNodeTonemap

    def __init__(
        self,
        image: InputColor = None,
        type: InputMenu
        | Literal["R/D Photoreceptor", "Rh Simple"] = "R/D Photoreceptor",
        key: InputFloat = 0.18,
        balance: InputFloat = 1.0,
        gamma: InputFloat = 1.0,
        intensity: InputFloat = 0.0,
        contrast: InputFloat = 0.0,
        light_adaptation: InputFloat = 0.0,
        chromatic_adaptation: InputFloat = 0.0,
    ):
        super().__init__()
        key_args = {
            "Image": image,
            "Type": type,
            "Key": key,
            "Balance": balance,
            "Gamma": gamma,
            "Intensity": intensity,
            "Contrast": contrast,
            "Light Adaptation": light_adaptation,
            "Chromatic Adaptation": chromatic_adaptation,
        }

        self._establish_links(**key_args)

    @classmethod
    def r_d_photoreceptor(
        cls,
        image: InputColor = None,
        intensity: InputFloat = 0.0,
        contrast: InputFloat = 0.0,
        light_adaptation: InputFloat = 0.0,
        chromatic_adaptation: InputFloat = 0.0,
    ) -> "Tonemap":
        """Create Tonemap node with type 'R/D Photoreceptor'."""
        return cls(
            image=image,
            intensity=intensity,
            contrast=contrast,
            light_adaptation=light_adaptation,
            chromatic_adaptation=chromatic_adaptation,
            type="R/D Photoreceptor",
        )

    @classmethod
    def rh_simple(
        cls,
        image: InputColor = None,
        key: InputFloat = 0.18,
        balance: InputFloat = 1.0,
        gamma: InputFloat = 1.0,
    ) -> "Tonemap":
        """Create Tonemap node with type 'Rh Simple'."""
        return cls(image=image, key=key, balance=balance, gamma=gamma, type="Rh Simple")

    @property
    def i_image(self) -> Socket:
        """Input socket: Image"""
        return self.inputs.get("Image")

    @property
    def i_type(self) -> Socket:
        """Input socket: Type"""
        return self.inputs.get("Type")

    @property
    def i_key(self) -> Socket:
        """Input socket: Key"""
        return self.inputs.get("Key")

    @property
    def i_balance(self) -> Socket:
        """Input socket: Balance"""
        return self.inputs.get("Balance")

    @property
    def i_gamma(self) -> Socket:
        """Input socket: Gamma"""
        return self.inputs.get("Gamma")

    @property
    def i_intensity(self) -> Socket:
        """Input socket: Intensity"""
        return self.inputs.get("Intensity")

    @property
    def i_contrast(self) -> Socket:
        """Input socket: Contrast"""
        return self.inputs.get("Contrast")

    @property
    def i_light_adaptation(self) -> Socket:
        """Input socket: Light Adaptation"""
        return self.inputs.get("Light Adaptation")

    @property
    def i_chromatic_adaptation(self) -> Socket:
        """Input socket: Chromatic Adaptation"""
        return self.inputs.get("Chromatic Adaptation")

